function drawVisualizer() {
  const canvas = canvasRef.value
  const ctx = canvas.getContext('2d')
  const width = canvas.width
  const height = canvas.height
  const centerX = width / 2
  const centerY = height / 2
  
  analyser.fftSize = 512


  let currentRadius = 40 // Radio base
  const baseRadius = 40
  const maxExpand = 100 // Cuánto puede crecer máximo

  function draw() {
    animationId = requestAnimationFrame(draw)
    analyser.getByteFrequencyData(dataArray)

    // 1. Obtener intensidad (promedio de graves)
    let sum = 0
    for (let i = 0; i < 15; i++) sum += dataArray[i]
    const intensity = sum / 15

    // 2. Calcular radio objetivo y suavizar (Interpolación)
    // El 0.15 controla qué tan "elástico" se siente el crecimiento
    const targetRadius = baseRadius + (intensity * (maxExpand / 255))
    currentRadius += (targetRadius - currentRadius) * 0.15

    ctx.clearRect(0, 0, width, height)

    // 3. Crear el gradiente difuminado (Aura)
    // El gradiente va desde el centro hacia el borde del radio actual
    const gradient = ctx.createRadialGradient(
      centerX, centerY, baseRadius * 0.5, 
      centerX, centerY, currentRadius
    )

    // Colores azules difuminados
    gradient.addColorStop(0, "rgba(0, 150, 255, 0.8)")   // Centro sólido
    gradient.addColorStop(0.5, "rgba(0, 100, 255, 0.3)") // Medio transparente
    gradient.addColorStop(1, "rgba(0, 50, 255, 0)")      // Borde totalmente difuso

    // 4. Dibujar el círculo
    ctx.beginPath()
    ctx.fillStyle = gradient
    ctx.arc(centerX, centerY, currentRadius, 0, Math.PI * 2)
    ctx.fill()

    // Opcional: Un anillo exterior brillante muy fino
    ctx.beginPath()
    ctx.lineWidth = 2
    ctx.strokeStyle = `rgba(100, 200, 255, ${intensity / 255})`
    ctx.arc(centerX, centerY, currentRadius, 0, Math.PI * 2)
    ctx.stroke()
  }
  draw()
}

function shuffleArray(length) {
    const indices = [...Array(length).keys()]
    for (let i = indices.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1))
            ;[indices[i], indices[j]] = [indices[j], indices[i]]
    }
    return indices
}
function CloseMoment() {
    moment.value = false
}


function loadTrack(index) {
    const song = songs.value[index]
    if (!song) return
    audio.src = song.url
    durationSong.value = 0
    audio.load()
    audio.muted = false
    audio.volume = 1
    stopPlaybackTimer()
    // si quieres reproducir inmediatamente SOLO si isPlaying está true
    if (isPlaying.value) {
        // Asegura que el audioContext esté activo antes de play
        if (audioContext && audioContext.state === 'suspended') {
            audioContext.resume().catch(e => console.warn('resume falló', e))
        }
        audio.play().then(() => {
            isPlaying.value = true
            startPlaybackTimer()
        }).catch(err => {
            console.warn('iOS puede haber bloqueado la reproducción:', err)
        })
    } else {
        isPlaying.value = false
    }
}

// function toggleLoop() {
//     isLoop.value = !isLoop.value
// }
function toggleLoop() {
    isLoop.value = !isLoop.value
    audio.loop = isLoop.value
}

async function togglePlay() {
    try {
        if (audioContext && audioContext.state === 'suspended') {
            await audioContext.resume()
        }
    } catch (err) {
        console.warn('No se pudo reanudar audioContext:', err)
    }

    if (audio.paused) {
        try {
            // asegúrate el elemento no esté mute y volumen ok
            audio.muted = false
            audio.volume = 1
            await audio.play()
            isPlaying.value = true
            startPlaybackTimer()
        } catch (err) {
            console.warn('Error al play (iOS puede bloquear):', err)
        }
    } else {
        SetPlay(1)
        audio.pause()
        isPlaying.value = false
        stopPlaybackTimer()
        countPause.value++;
        if (!hasShownMomentThisSession() && (playbackSeconds.value >= 15 | (playbackSeconds.value >= 14 && countPause.value > 1))) {
            moment.value = true;
            playbackSeconds.value = 0;
            hasShownMessage.value = true
            markMomentAsShown()
            countPause.value = 0
        }
    }
}


function startPlaybackTimer() {
    if (playbackInterval) return // Evita múltiples intervalos

    playbackInterval = setInterval(() => {
        playbackSeconds.value++
        durationSong.value++
    }, 1000)
}

function stopPlaybackTimer() {
    clearInterval(playbackInterval)
    playbackInterval = null
}

function nextTrack() {
    SetPlay(0)
    if (isShuffle.value) {
        if (shuffledIndices.length === 0) {
            shuffledIndices = shuffleArray(songs.value.length)
        }
        currentIndex.value = shuffledIndices.shift()
    } else {
        currentIndex.value = (currentIndex.value + 1) % songs.value.length
    }
    isPlaying.value = true
    loadTrack(currentIndex.value)
}

function prevTrack() {
    SetPlay(0)
    if (isShuffle.value) {
        if (shuffledIndices.length === 0) {
            shuffledIndices = shuffleArray(songs.value.length)
        }
        currentIndex.value = shuffledIndices.shift()
    } else {
        currentIndex.value = (currentIndex.value - 1 + songs.value.length) % songs.value.length
    }
    isPlaying.value = true
    loadTrack(currentIndex.value)
}

function toggleShuffle() {
    isShuffle.value = !isShuffle.value

    if (isShuffle.value) {
        shuffledIndices = shuffleArray(songs.value.length)
        // Evita repetir la canción actual
        shuffledIndices = shuffledIndices.filter(i => i !== currentIndex.value)
    } else {
        shuffledIndices = []
    }
}

function seekAudio() {
    audio.currentTime = currentTime.value
}

audio.addEventListener('timeupdate', () => {
    currentTime.value = audio.currentTime
    duration.value = audio.duration || 0
})

