})

onBeforeUnmount(() => {
    cancelAnimationFrame(animationId)
    audio.pause()
    audio.src = ''
    if (audioContext) audioContext.close()
})



const editingIndex = ref(null)
const editedName = ref('')

function playSong(index) {
    isPlaying.value = true
    currentIndex.value = index
    loadTrack(index)
    startPlaybackTimer()
    isPlaying.value = true
}

function removeSong(index) {
    const songToDelete = songs.value[index]

    const isCurrent = currentIndex.value === index
    if (isCurrent) {
        audio.pause()
        isPlaying.value = false
        stopPlaybackTimer()
    }

    // if (currentIndex.value === index) {
    //     audio.pause()
    // }
    // Ajustamos currentIndex si es necesario
    if (songs.value.length === 0) {
        // No quedan canciones
        currentIndex.value = 0
        audio.src = ''
        return
    }
    if (currentIndex.value > index) {
        // Si la canción eliminada estaba antes de la actual, decrementamos el índice
        currentIndex.value -= 1
    } else if (currentIndex.value === index) {
        // Si eliminamos la canción actual, cargamos la siguiente disponible
        if (currentIndex.value >= songs.value.length) {
            currentIndex.value = 0
        }
    }

    // Llamamos a la API para eliminar favorito
    DeleteFavorite(songToDelete.id)
    // Si queda alguna canción, la cargamos y reproducimos
    if (songs.value.length > 0) {
        loadTrack(currentIndex.value)
        isPlaying.value = true
        startPlaybackTimer()
    }
    songs.value.splice(index, 1)
    if (currentIndex.value >= songs.value.length) {
        currentIndex.value = 0
    }
    // DeleteFavorite()
    // loadTrack(currentIndex.value)
}

async function DeleteFavorite(audiotecaId) {
    try {
        const sesion = localStorage.getItem("token")
        if (!sesion) return
        // const currentAudio = songs.value[currentIndex.value]

        const response = await fetch(`${API_BASE_URL}/api/audioteca/SetAudiotecaEstatus`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ audioteca: audiotecaId + '' })
        })

        if (!response.ok) throw new Error("Error en la petición")

    } catch (error) {
        console.error("Error al cargar audios:", error)
    }
}


function editSong(index) {
    editingIndex.value = index
    editedName.value = songs.value[index].name
}

async function saveEdit(index) {
    const newName = editedName.value.trim()
    if (!newName) {
        editingIndex.value = null
        return
    }

    // Actualizamos el nombre localmente
    songs.value[index].name = newName

    // Llamamos a la API para actualizar el nombre en el backend
    try {
        await ChangeName(songs.value[index].id, newName)
    } catch (error) {
        console.error("Error al cambiar el nombre en el servidor:", error)
        // Opcional: revertir el cambio local si falla la API
        // songs.value[index].name = originalName
    }

    editingIndex.value = null

    // if (editedName.value.trim()) {
    //     songs.value[index].name = editedName.value.trim()
    // }
    // editingIndex.value = null
}

