            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ idaudioteca: audiotecaId + '', name: nameAudio })
        })

        if (!response.ok) throw new Error("Error en la petición")

    } catch (error) {
        console.error("Error al cargar audios:", error)
    }
}

